final:
module top_module(E,S,obf_D,Y);input E;
input [2:0] S;
input [7:0] obf_D;
output Y;
reg Y;

always @(E,S,obf_D)
begin
	if(E) Y = 1'b0;
	else
	begin
		case(S)
			3'b000 : Y = obf_D[0];
			3'b001 : Y = obf_D[1];
			3'b010 : Y = obf_D[2];
			3'b011 : Y = obf_D[3];
			3'b100 : Y = obf_D[4];
			3'b101 : Y = obf_D[5];
			3'b110 : Y = obf_D[6];
			3'b111 : Y = obf_D[7];
		endcase
	end
end
endmodule
